function decodeString(s) {
  const stack = [];
  let currentStr = '';
  let currentNum = 0;
  for (const ch of s) {
    if (ch >= '0' && ch <= '9') {
      currentNum = currentNum * 10 + Number(ch);
      continue;
    }
    if (ch === '[') {
      stack.push([currentStr, currentNum]);
      currentStr = '';
      currentNum = 0;
      continue;
    }
    if (ch === ']') {
      const [prevStr, num] = stack.pop();
      currentStr = prevStr + currentStr.repeat(num);
      continue;
    }
    currentStr += ch;
  }
  return currentStr;
}
